```javascript
var TWO_PI = 6.283;
var GOLDEN_RATIO = 1.618;
var SQRT_HALF = 0.707;

var physicsConfig = {
  attraction: 4000,
  elasticCoeff: 0.004,
  amplification: 0.92,
  gravity: 0.0003,
  streamCap: 40,
  streamDecay: 0.04,
  theta: 0.06
};

var hubNode = { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 };
var alphaNode = { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 };
var betaNode = { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 };
var gammaNode = { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 };
var deltaNode = { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 };
var epsilonNode = { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 };

var nodes = [hubNode, alphaNode, betaNode, gammaNode, deltaNode, epsilonNode];

var edges = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var smoothedCamera = { x: 400, y: 300, zoom: 1 };
var targetCamera = { x: 400, y: 300, zoom: 1 };
var particles = [];
var tickCount = 0;

function findNodeById(nodeId) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Coulomb repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var repulsionMagnitude = physicsConfig.attraction / (dist * dist);
      var forceX = (dx / dist) * repulsionMagnitude;
      var forceY = (dy / dist) * repulsionMagnitude;
      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Spring attraction along edges
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNodeById(edges[e].a);
    var nodeB = findNodeById(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var springForce = (edges[e].k || physicsConfig.elasticCoeff) * displacement;
    nodeA.vx += (dx / dist) * springForce;
    nodeA.vy += (dy / dist) * springForce;
    nodeB.vx -= (dx / dist) * springForce;
    nodeB.vy -= (dy / dist) * springForce;
  }

  // Integrate velocity, apply gravity toward center, apply damping
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * physicsConfig.gravity;
    nodes[n].vy += (300 - nodes[n].y) * physicsConfig.gravity;
    nodes[n].vx *= physicsConfig.amplification;
    nodes[n].vy *= physicsConfig.amplification;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

function spawnParticle() {
  if (particles.length >= physicsConfig.streamCap) return;
  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TWO_PI;
  var speed = 0.3 + Math.random() * SQRT_HALF;
  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF
  });
}

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var particle = particles[i];
    particle.age++;
    if (particle.age > particle.maxAge) {
      particles.splice(i, 1);
      continue;
    }
    var decayFactor = 1 - physicsConfig.streamDecay * 0.125;
    particle.vx *= decayFactor;
    particle.vy *= decayFactor;
    particle.x += particle.vx;
    particle.y += particle.vy;
  }
}

function updateCamera() {
  smoothedCamera.x += (targetCamera.x - smoothedCamera.x) * physicsConfig.theta;
  smoothedCamera.y += (targetCamera.y - smoothedCamera.y) * physicsConfig.theta;
  smoothedCamera.zoom += (targetCamera.zoom - smoothedCamera.zoom) * physicsConfig.theta;
}

function tick() {
  applyForces();
  updateParticles();
  updateCamera();
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(tick, 16);
```

This is a **force-directed graph layout** simulation with Coulomb repulsion between all nodes, Hooke's law spring forces along edges, gravitational centering, velocity damping, decorative particle streaming from nodes, and smooth camera interpolation.
